			g.baseCommitSHA = strings.TrimSpace(out)
		} else if out, err := g.runGitCommand(g.worktreePath, "rev-parse", "HEAD"); err == nil {
			g.baseCommitSHA = strings.TrimSpace(out)
		}
	}

	return nil
